public int makeStringSorted(String s) {
    final int mod = 1000000007;
    int n = s.length();
    int[] fact = new int[n + 1];
    int[] inv = new int[n + 1];
    fact[0] = inv[0] = 1;
    for (int i = 1; i <= n; ++i) {
        fact[i] = (int)((1L * fact[i - 1] * i) % mod);
        inv[i] = (int)((1L * inv[i - 1] * (mod - mod / i)) % mod);
    }
    int ans = 0;
    for (int i = 0; i < n; ++i) {
        int less_than = 0;
        for (int j = i + 1; j < n; ++j) {
            if (s.charAt(j) < s.charAt(i)) ++less_than;
        }
        ans = (int)((ans + 1L * less_than * fact[n - i - 1]) % mod);
    }
    return ans;
}
```

